solution_code:
#include <iostream>
#include <iomanip>

class Duration {
    int m_min{};
    int m_sec{};
public:
    Duration(int min, int sec) : m_min{min}, m_sec{sec} {}
    int minutes() const { return m_min; }
    int seconds() const { return m_sec; }
};

Duration operator+(const Duration& a, const Duration& b) {
    int totalSec = a.seconds() + b.seconds();
    int carry = totalSec / 60;
    int remSec = totalSec % 60;
    int totalMin = a.minutes() + b.minutes() + carry;
    return Duration{totalMin, remSec};
}

int main() {
    int m1, s1, m2, s2;
    std::cin >> m1 >> s1;
    std::cin >> m2 >> s2;
    Duration d1{m1, s1}, d2{m2, s2};
    Duration r = d1 + d2;
    std::cout << r.minutes() << ":" << std::setfill('0') << std::setw(2) << r.seconds() << "\n";
    return 0;
}

