#include <iostream>

class Rectangle {
    int m_w{}, m_h{};
public:
    Rectangle(int w, int h) : m_w{w}, m_h{h} {}
    int area() const { return m_w * m_h; }
};

bool operator<(const Rectangle& a, const Rectangle& b) {
    return a.area() < b.area();
}

int main() {
    int w1, h1, w2, h2;
    std::cin >> w1 >> h1;
    std::cin >> w2 >> h2;
    Rectangle a{w1, h1}, b{w2, h2};
    if (a < b)
        std::cout << "A is smaller\n";
    else if (b < a)
        std::cout << "B is smaller\n";
    else
        std::cout << "Equal\n";
    return 0;
}
